import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Plus, Search, Eye, Trash2, FileOutput, Check, X, Filter, FileDown, Send, Mail } from 'lucide-react';
import { getPresupuestos, deletePresupuesto, updatePresupuesto, convertirAOrden, getPresupuestoPdf, enviarPresupuestoWhatsApp, enviarPresupuestoEmail } from '../../services/api';
import { formatCurrency, formatDate, badgeClass } from '../../utils/formatters';
import ConfirmDialog from '../common/ConfirmDialog';
import Loading from '../common/Loading';

export default function PresupuestosList() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [estado, setEstado] = useState('');
  const [material, setMaterial] = useState('');
  const [fechaDesde, setFechaDesde] = useState('');
  const [fechaHasta, setFechaHasta] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [deleteId, setDeleteId] = useState(null);
  const navigate = useNavigate();

  const load = useCallback(() => {
    setLoading(true);
    getPresupuestos({
      search: search || undefined,
      estado: estado || undefined,
      material: material || undefined,
      fecha_desde: fechaDesde || undefined,
      fecha_hasta: fechaHasta || undefined,
    }).then((res) => {
      setData(res.data);
      setLoading(false);
    });
  }, [search, estado, material, fechaDesde, fechaHasta]);

  useEffect(() => { load(); }, [load]);

  const handleDelete = async () => {
    if (!deleteId) return;
    await deletePresupuesto(deleteId);
    setDeleteId(null);
    load();
  };

  const handleCambiarEstado = async (id, estado) => {
    await updatePresupuesto(id, { estado });
    load();
  };

  const handleConvertir = async (id) => {
    if (!window.confirm('¿Convertir este presupuesto en orden de trabajo?')) return;
    try {
      await convertirAOrden(id);
      load();
    } catch (err) {
      alert(err.response?.data?.detail || 'Error al convertir');
    }
  };

  const handleEnviarWhatsApp = async (id) => {
    try {
      await enviarPresupuestoWhatsApp(id);
      alert('WhatsApp enviado correctamente');
    } catch (err) {
      alert(err.response?.data?.detail || 'Error al enviar WhatsApp');
    }
  };

  const handleEnviarEmail = async (id) => {
    try {
      await enviarPresupuestoEmail(id);
      alert('Email enviado correctamente');
    } catch (err) {
      alert(err.response?.data?.detail || 'Error al enviar email');
    }
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 700 }}>Presupuestos</h1>
        <button className="btn btn-primary" onClick={() => navigate('/presupuestos/nuevo')}>
          <Plus size={16} /> Nuevo Presupuesto
        </button>
      </div>

      <div className="card" style={{ marginBottom: 16 }}>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'center' }}>
          <div style={{ position: 'relative', flex: 1, minWidth: 250 }}>
            <Search size={18} style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#94a3b8' }} />
            <input className="input" placeholder="Nro, cliente, teléfono, material..." value={search} onChange={(e) => setSearch(e.target.value)} style={{ paddingLeft: 40 }} />
          </div>
          <select className="input" style={{ width: 160 }} value={estado} onChange={(e) => setEstado(e.target.value)}>
            <option value="">Todos los estados</option>
            <option value="Pendiente">Pendiente</option>
            <option value="Aprobado">Aprobado</option>
            <option value="Rechazado">Rechazado</option>
            <option value="Convertido">Convertido</option>
          </select>
          <button className="btn btn-outline" onClick={() => setShowFilters(!showFilters)}>
            <Filter size={16} /> Filtros
          </button>
        </div>
        {showFilters && (
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', marginTop: 12, paddingTop: 12, borderTop: '1px solid #e2e8f0' }}>
            <div className="form-group" style={{ margin: 0 }}>
              <label style={{ fontSize: 12 }}>Material</label>
              <input className="input" placeholder="Filtrar por material..." value={material} onChange={(e) => setMaterial(e.target.value)} />
            </div>
            <div className="form-group" style={{ margin: 0 }}>
              <label style={{ fontSize: 12 }}>Fecha desde</label>
              <input className="input" type="date" value={fechaDesde} onChange={(e) => setFechaDesde(e.target.value)} />
            </div>
            <div className="form-group" style={{ margin: 0 }}>
              <label style={{ fontSize: 12 }}>Fecha hasta</label>
              <input className="input" type="date" value={fechaHasta} onChange={(e) => setFechaHasta(e.target.value)} />
            </div>
          </div>
        )}
      </div>

      {loading ? <Loading /> : (
        <div className="card">
          <div className="table-container">
            <table>
              <thead>
                <tr>
                  <th>Número</th>
                  <th>Cliente</th>
                  <th>Material</th>
                  <th>Total</th>
                  <th>Estado</th>
                  <th>Fecha</th>
                  <th style={{ width: 140 }}>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {data.map((p) => (
                  <tr key={p.id}>
                    <td style={{ fontWeight: 600, fontFamily: 'monospace' }}>{p.numero}</td>
                    <td>{p.cliente_nombre || '-'}</td>
                    <td>{p.material || '-'}</td>
                    <td style={{ fontWeight: 600 }}>{formatCurrency(p.total)} <span style={{ fontSize: 11, color: '#94a3b8' }}>{p.moneda || 'ARS'}</span></td>
                    <td><span className={badgeClass(p.estado)}>{p.estado}</span></td>
                    <td>{formatDate(p.created_at)}</td>
                    <td>
                      <div style={{ display: 'flex', gap: 6 }}>
                        <button className="btn btn-outline" style={{ padding: '4px 8px' }} onClick={() => window.open(getPresupuestoPdf(p.id), '_blank')} title="Descargar PDF">
                          <FileDown size={14} />
                        </button>
                        <button className="btn btn-outline" style={{ padding: '4px 8px' }} onClick={() => navigate(`/presupuestos/${p.id}`)}>
                          <Eye size={14} />
                        </button>
                        {p.estado === 'Pendiente' && (
                          <>
                            <button className="btn btn-success" style={{ padding: '4px 8px' }} onClick={() => handleCambiarEstado(p.id, 'Aprobado')} title="Aprobar">
                              <Check size={14} />
                            </button>
                            <button className="btn btn-danger" style={{ padding: '4px 8px' }} onClick={() => handleCambiarEstado(p.id, 'Rechazado')} title="Rechazar">
                              <X size={14} />
                            </button>
                          </>
                        )}
                        {p.estado === 'Aprobado' && (
                          <button className="btn btn-success" style={{ padding: '4px 8px' }} onClick={() => handleConvertir(p.id)} title="Convertir a Orden">
                            <FileOutput size={14} />
                          </button>
                        )}
                        <button className="btn btn-success" style={{ padding: '4px 8px' }} onClick={() => handleEnviarWhatsApp(p.id)} title="Enviar por WhatsApp">
                          <Send size={14} />
                        </button>
                        <button className="btn btn-outline" style={{ padding: '4px 8px' }} onClick={() => handleEnviarEmail(p.id)} title="Enviar por Email">
                          <Mail size={14} />
                        </button>
                        <button className="btn btn-danger" style={{ padding: '4px 8px' }} onClick={() => setDeleteId(p.id)}>
                          <Trash2 size={14} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
                {data.length === 0 && (
                  <tr><td colSpan={7} style={{ textAlign: 'center', padding: 40, color: '#94a3b8' }}>No hay presupuestos</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      <ConfirmDialog isOpen={!!deleteId} onClose={() => setDeleteId(null)} onConfirm={handleDelete} title="Eliminar presupuesto" message="¿Estás seguro?" />
    </div>
  );
}
